interface TreeNode<T> {
  value: T;
  left: TreeNode<T> | null;
  right: TreeNode<T> | null;
}

function insert<T>(node: TreeNode<T> | null, value: T, cmp: (a: T, b: T) => number): TreeNode<T> {
  if (node === null) return { value, left: null, right: null };
  if (cmp(value, node.value) < 0) node.left = insert(node.left, value, cmp);
  else node.right = insert(node.right, value, cmp);
  return node;
}
